noncompliant:
// Function pointer as parameter - Noncompliant
void processData(int (*callback)(int)) {
    int result = callback(42);
    // Process result
}

// Another example with function pointer
void executeOperation(void (*operation)()) {
    operation();
}

compliant:
// Better: Use std::function
#include <functional>

void processData(std::function<int(int)> callback) {
    int result = callback(42);
    // Process result
}

// Or use template parameter
template<class Callback>
void executeOperation(Callback operation) {
    operation();
}
